        self._rows: dict[str, Row] = {}

    def lookup(self, key: str) -> Row | None:
        return self._rows.get(key)

def extract_model_name(response: object) -> str | None:
    # response is a raw provider reply from a third-party LLM SDK; the SDK
    # version decides whether `.model` exists, so its shape is not first-party-guaranteed.
    model = getattr(response, "model", None)
    if model is None:
        return None  # record absence as None; do not fabricate a model id
    if not isinstance(model, str):
        raise TypeError(f"provider returned non-str model: {type(model).__name__}")
    return model

