def group_rows_by_kind(rows: list[Row]) -> dict[str, list[Row]]:
    # Accumulate rows into per-kind buckets. setdefault builds the bucket on
    # first sight of a key; this is intentional accumulation, not missing-key masking.
    groups: dict[str, list[Row]] = {}
    for row in rows:
        groups.setdefault(row.kind, []).append(row)
    return groups

def _collect_rows(self, plugin: TransformPlugin, row: Row) -> list[Row]:
    plugin_result = plugin.transform(row)
    return list(getattr(plugin_result, "rows", []))

